sql:
SELECT description 
FROM products 
WHERE price > (SELECT AVG(price) FROM products);

SELECT status_notes
FROM order_status
WHERE status = 'pending';

SELECT product_id, quantity, unit_price
FROM order_items
WHERE order_id = 839;

external_knowledge:
- 'hidden treasures' refers to products that are not marked as 'shipped';
- 'positive stock level' indicates the product is still available and has not been sold out;
- 'gathering more admirers than the crowd norm' refers to products with orders above the average order count;
- 'shine brighter as stars in our product catalog' signifies that these items have higher popularity and are highlighted as top choices.

sql:
SELECT note, created 
FROM order_notes 
WHERE order_id = 838;

SELECT SUM(quantity) AS total_quantity
FROM order_items
WHERE product_id = 0;

SELECT order_items.order_id, SUM(order_items.unit_price * order_items.quantity) AS 'Total Cost'
FROM order_items
GROUP BY order_items.order_id;

external_knowledge:
- "shining star" refers metaphorically to the salesman who has achieved the highest success or performance; 
- "leading the pack in earning potential" refers to having the highest commission rate among the sales team;
- The contact details include name and email.

sql:
SELECT name, company
FROM customers
WHERE vat_number IS NOT NULL AND company IS NOT NULL;

SELECT DISTINCT oi.order_id, oi.product_id
FROM order_items oi
WHERE oi.quantity > 10;

SELECT name, email, commission_rate 
FROM salesmen
ORDER BY commission_rate DESC;

SELECT customers.name, transactions.amount
FROM customers
LEFT JOIN transactions ON customers.id = transactions.order_id;
